import { GoogleGenAI, Type } from "@google/genai";

const apiKey = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey });

export const askRitualAssistant = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: query,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        systemInstruction: `You are the "Rafeeq Al-Haramain" AI Assistant. 
        Your ONLY purpose is to answer questions regarding Hajj and Umrah rituals based on official Saudi Arabian religious authorities and Haramain guidelines. 
        If a question is outside these topics, politely decline to answer. 
        Always cite that this information is for educational purposes and users should consult official Nusuk or Haramain sources for final rulings.`
      }
    });
    return response.text;
  } catch (error) {
    console.error("AI Assistant Error:", error);
    return "I am unable to connect to the guidance system. Please consult official Haramain guides.";
  }
};

export const searchHaramServices = async (serviceType: string, lat?: number, lng?: number) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find official ${serviceType} locations inside the Grand Mosque (Masjid al-Haram) area. Provide verified location names and descriptions.`,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });
    return {
      text: response.text,
      links: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Search Grounding Error:", error);
    return null;
  }
};

