export default Layout;

import React, { useState, useEffect } from 'react';
import { COLORS, TAWAF_DUAS } from '../constants';

interface TawafCounterProps {
  language: 'en' | 'ar';
}

const TawafCounter: React.FC<TawafCounterProps> = ({ language }) => {
  const [count, setCount] = useState(0);
  const [isExpanded, setIsExpanded] = useState(false);
  const isAr = language === 'ar';

  const increment = () => {
    if (count < 7) {
      setCount(prev => prev + 1);
      // Logic for haptic feedback would go here in Native
    }
  };

  const reset = () => setCount(0);

  const radius = 90;
  const circumference = 2 * Math.PI * radius;
  const progress = (count / 7) * circumference;

  return (
    <div className="px-6 py-4 space-y-6">
      <div className="relative flex flex-col items-center justify-center p-12 glass-card rounded-[40px] gold-shadow overflow-hidden">
        {/* Pseudo-3D Background Layer */}
        <div className="absolute inset-0 opacity-5 pointer-events-none">
          <svg width="100%" height="100%" viewBox="0 0 100 100">
            <circle cx="50" cy="50" r="45" fill="none" stroke={COLORS.GOLD} strokeWidth="0.5" strokeDasharray="2 2" />
          </svg>
        </div>

        <div className="relative w-64 h-64 flex items-center justify-center">
          <svg className="absolute w-full h-full -rotate-90">
            <circle
              cx="128"
              cy="128"
              r={radius}
              fill="none"
              stroke="#E5E7EB"
              strokeWidth="12"
              className="opacity-20"
            />
            <circle
              cx="128"
              cy="128"
              r={radius}
              fill="none"
              stroke={COLORS.GOLD}
              strokeWidth="12"
              strokeDasharray={circumference}
              strokeDashoffset={circumference - progress}
              strokeLinecap="round"
              className="transition-all duration-700 ease-out"
            />
          </svg>
          <div className="flex flex-col items-center">
            <span className="text-7xl font-bold" style={{ color: COLORS.BLACK }}>{count}</span>
            <span className="text-sm font-semibold tracking-widest text-gray-400 uppercase">
              {isAr ? 'أشواط' : 'Laps'}
            </span>
          </div>
        </div>

        <div className="mt-8 flex space-x-4 space-x-reverse">
          <button
            onClick={increment}
            className="px-10 py-4 bg-[#D4AF37] text-white rounded-2xl font-bold shadow-lg tap-scale active:bg-[#C09A2F]"
          >
            {isAr ? 'شوط جديد' : 'Next Lap'}
          </button>
          <button
            onClick={reset}
            className="p-4 bg-white border border-gray-100 text-gray-400 rounded-2xl shadow-sm tap-scale"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
          </button>
        </div>
      </div>

      <div className="glass-card rounded-3xl overflow-hidden border border-gray-100 transition-all duration-500">
        <button 
          onClick={() => setIsExpanded(!isExpanded)}
          className="w-full flex items-center justify-between p-6 bg-white"
        >
          <div className="flex items-center space-x-3 space-x-reverse">
            <div className="w-8 h-8 rounded-full bg-[#D4AF37]/10 flex items-center justify-center">
              <svg className="w-4 h-4 text-[#D4AF37]" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
            </div>
            <span className="font-bold text-gray-800">{isAr ? 'دليل الطواف' : 'Tawaf Guide'}</span>
          </div>
          <svg className={`w-5 h-5 transition-transform ${isExpanded ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"/></svg>
        </button>

        <div className={`overflow-hidden transition-all duration-500 ${isExpanded ? 'max-h-[500px]' : 'max-h-0'}`}>
          <div className="p-6 pt-0 space-y-4 text-sm text-gray-600 leading-relaxed">
            <p className="font-medium text-[#D4AF37]">{isAr ? 'من أين يبدأ؟' : 'Where to start?'}</p>
            <p>{isAr ? 'يبدأ الطواف من الحجر الأسود وينتهي عنده.' : 'Tawaf starts and ends at the Black Stone (Al-Hajar al-Aswad).'}</p>

            <div className="bg-gray-50 p-4 rounded-2xl italic border-r-4 border-[#D4AF37]">
              <p className="text-gray-800 mb-2 font-amiri text-lg">{TAWAF_DUAS[0].text}</p>
              <p className="text-xs text-gray-500">{TAWAF_DUAS[0].translation}</p>
            </div>

            <a 
              href="https://alharamain.gov.sa" 
              target="_blank" 
              className="block w-full text-center py-3 bg-gray-100 text-[#D4AF37] font-bold rounded-xl mt-4"
            >
              {isAr ? 'المصدر الرسمي' : 'Official Source'}
            </a>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TawafCounter;

import React, { useState } from 'react';
import { COLORS } from '../constants';

interface SaiCounterProps {
  language: 'en' | 'ar';
}

const SaiCounter: React.FC<SaiCounterProps> = ({ language }) => {
  const [laps, setLaps] = useState(0);
  const [direction, setDirection] = useState<'toMarwa' | 'toSafa'>('toMarwa');
  const [isExpanded, setIsExpanded] = useState(false);
  const isAr = language === 'ar';

  const increment = (newDir: 'toMarwa' | 'toSafa') => {
    if (laps < 7 && newDir !== direction) {
      setLaps(prev => prev + 1);
      setDirection(newDir);
    } else if (laps === 0 && newDir === 'toMarwa') {
      setLaps(1);
      setDirection('toMarwa');
    }
  };

  return (
    <div className="px-6 py-4 space-y-6">
      <div className="glass-card rounded-[40px] p-8 space-y-8 gold-shadow">
        <div className="flex justify-between items-center px-4">
          <div className="flex flex-col items-center">
            <div className={`w-16 h-16 rounded-3xl flex items-center justify-center transition-all ${direction === 'toSafa' ? 'bg-[#D4AF37] text-white' : 'bg-gray-100 text-gray-400'}`}>
              <span className="font-bold">S</span>
            </div>
            <span className="mt-2 text-xs font-bold text-gray-500">{isAr ? 'الصفا' : 'Safa'}</span>
          </div>
          <div className="flex-1 px-4">
            <div className="h-1 bg-gray-100 rounded-full relative overflow-hidden">
               <div 
                 className="absolute inset-0 bg-[#D4AF37] transition-all duration-1000" 
                 style={{ width: `${(laps/7) * 100}%` }}
               />
            </div>
          </div>
          <div className="flex flex-col items-center">
            <div className={`w-16 h-16 rounded-3xl flex items-center justify-center transition-all ${direction === 'toMarwa' ? 'bg-[#D4AF37] text-white' : 'bg-gray-100 text-gray-400'}`}>
              <span className="font-bold">M</span>
            </div>
            <span className="mt-2 text-xs font-bold text-gray-500">{isAr ? 'المروة' : 'Marwa'}</span>
          </div>
        </div>

        <div className="flex flex-col items-center justify-center py-4">
          <span className="text-6xl font-black text-[#1A1A1A]">{laps}</span>
          <span className="text-xs uppercase tracking-widest text-gray-400 font-bold mt-2">
            {isAr ? 'أشواط مكتملة' : 'Completed Laps'}
          </span>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <button
            onClick={() => increment('toMarwa')}
            disabled={direction === 'toMarwa' && laps > 0}
            className={`flex flex-col items-center p-6 rounded-3xl transition-all tap-scale ${direction === 'toSafa' || laps === 0 ? 'bg-white border-2 border-[#D4AF37] text-[#D4AF37]' : 'bg-gray-50 text-gray-300'}`}
          >
            <svg className="w-8 h-8 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
            <span className="text-sm font-bold">{isAr ? 'إلى المروة' : 'To Marwa'}</span>
          </button>
          <button
            onClick={() => increment('toSafa')}
            disabled={direction === 'toSafa'}
            className={`flex flex-col items-center p-6 rounded-3xl transition-all tap-scale ${direction === 'toMarwa' ? 'bg-white border-2 border-[#D4AF37] text-[#D4AF37]' : 'bg-gray-50 text-gray-300'}`}
          >
            <svg className="w-8 h-8 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            <span className="text-sm font-bold">{isAr ? 'إلى الصفا' : 'To Safa'}</span>
          </button>
        </div>
      </div>

      <div className="glass-card rounded-3xl overflow-hidden border border-gray-100">
        <button 
          onClick={() => setIsExpanded(!isExpanded)}
          className="w-full flex items-center justify-between p-6 bg-white"
        >
          <span className="font-bold text-gray-800">{isAr ? 'دليل السعي' : 'Sa’i Guide'}</span>
          <svg className={`w-5 h-5 transition-transform ${isExpanded ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"/></svg>
        </button>
        {isExpanded && (
          <div className="p-6 pt-0 space-y-4 text-sm text-gray-600">
            <p>{isAr ? 'يبدأ السعي من الصفا وينتهي في المروة.' : 'Sa’i starts at Safa and ends at Marwa.'}</p>
            <div className="grid grid-cols-2 gap-2 text-[10px] text-center font-bold">
              <div className="bg-gray-100 p-2 rounded-lg">1. Safa → Marwa</div>
              <div className="bg-gray-100 p-2 rounded-lg">2. Marwa → Safa</div>
              <div className="bg-gray-100 p-2 rounded-lg">3. Safa → Marwa</div>
              <div className="bg-gray-100 p-2 rounded-lg">4. Marwa → Safa</div>
              <div className="bg-gray-100 p-2 rounded-lg">5. Safa → Marwa</div>
              <div className="bg-gray-100 p-2 rounded-lg">6. Marwa → Safa</div>
              <div className="bg-[#D4AF37]/20 p-2 rounded-lg col-span-2">7. Safa → Marwa (End)</div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SaiCounter;

import React, { useState, useRef, useEffect } from 'react';
import { askRitualAssistant } from '../services/geminiService';
import { COLORS } from '../constants';

interface AIChatProps {
  language: 'en' | 'ar';
}

const AIChat: React.FC<AIChatProps> = ({ language }) => {
  const [messages, setMessages] = useState<{role: 'user' | 'assistant', content: string}[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isAr = language === 'ar';

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsLoading(true);

    const aiResponse = await askRitualAssistant(userMsg);
    setMessages(prev => [...prev, { role: 'assistant', content: aiResponse }]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-full bg-white relative">
      <div className="p-4 bg-gray-50 border-b border-gray-100">
        <div className="flex items-center space-x-3 space-x-reverse">
          <div className="w-10 h-10 rounded-2xl bg-[#D4AF37] flex items-center justify-center text-white shadow-lg">
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 14.5c-.83 0-1.5-.67-1.5-1.5s.67-1.5 1.5-1.5 1.5.67 1.5 1.5-.67 1.5-1.5 1.5zm1-3.5h-2V7h2v6z"/></svg>
          </div>
          <div>
            <h3 className="font-bold text-gray-800">{isAr ? 'المساعد الشرعي' : 'Ritual Assistant'}</h3>
            <p className="text-[10px] text-gray-400 font-medium">
              {isAr ? 'إجابات موثوقة من المصادر الرسمية' : 'Verified answers from official sources'}
            </p>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center space-y-4 opacity-50">
             <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center">
                <svg className="w-10 h-10 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
             </div>
             <p className="text-sm">{isAr ? 'اسأل أي شيء عن مناسك الحج والعمرة' : 'Ask anything about Hajj or Umrah rituals'}</p>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-3xl ${m.role === 'user' ? 'bg-[#D4AF37] text-white rounded-br-none' : 'bg-gray-100 text-gray-800 rounded-bl-none'}`}>
              <p className="text-sm leading-relaxed">{m.content}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-gray-100 p-4 rounded-3xl animate-pulse flex space-x-2">
              <div className="w-2 h-2 bg-gray-300 rounded-full"></div>
              <div className="w-2 h-2 bg-gray-300 rounded-full"></div>
              <div className="w-2 h-2 bg-gray-300 rounded-full"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-gray-100">
