import { GoogleGenAI, Type } from "@google/genai";
import { AIMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const askRitualAssistant = async (query: string, mode: AIMode, language: string) => {
  const instructions = {
    [AIMode.FATWA]: `You are a specialist in Hajj and Umrah rulings (Fatwa). 
      Provide concise, evidence-based answers strictly from the official Saudi Ifta (alifta.gov.sa) and Haramain sources. 
      Mention if there is a difference of opinion. Language: ${language}.`,
    [AIMode.TRANSLATION]: `You are a translator for religious terms used in the Haramain. 
      Translate the user's input accurately between ${language} and Arabic, focusing on ritual accuracy.`,
    [AIMode.EXPLANATION]: `You are a guide (Rafeeq). Explain the steps of ${query} in a simple, step-by-step manner for pilgrims. 
      Focus on location accuracy (e.g., floors, start/end points). Language: ${language}.`
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: query,
      config: {
        thinkingConfig: { thinkingBudget: 15000 },
        systemInstruction: instructions[mode] + " Always cite official sources at the bottom: alharamain.gov.sa"
      }
    });
    return response.text;
  } catch (error) {
    console.error("AI Error:", error);
    return "Unable to retrieve guidance. Please consult official guides on-site.";
  }
};

