import React, { useState } from 'react';
import { COLORS, TAWAF_DUAS } from '../constants';

interface TawafCounterProps {
  language: 'en' | 'ar';
  isDarkMode: boolean;
}

const TawafCounter: React.FC<TawafCounterProps> = ({ language, isDarkMode }) => {
  const [count, setCount] = useState(0);
  const isAr = language === 'ar';

  const getLapText = (c: number) => {
    if (!isAr) return `Lap ${c} of 7`;
    if (c === 1) return 'الشوط الأول';
    if (c === 2) return 'الشوط الثاني';
    if (c === 3) return 'الشوط الثالث';
    if (c === 4) return 'الشوط الرابع';
    if (c === 5) return 'الشوط الخامس';
    if (c === 6) return 'الشوط السادس';
    if (c === 7) return 'الشوط السابع';
    return 'لم يبدأ بعد';
  };

  const increment = () => { if (count < 7) setCount(prev => prev + 1); };
  const reset = () => setCount(0);

  return (
    <div className="px-6 py-4 space-y-6 animate-in slide-in-from-bottom-10 duration-500">
      <div className={`relative flex flex-col items-center justify-center p-12 rounded-[48px] border-2 border-[#D4AF37]/20 transition-all ${isDarkMode ? 'bg-slate-800' : 'bg-white shadow-xl'}`}>
        <div className="relative w-56 h-56 flex items-center justify-center">
          <svg className="absolute w-full h-full -rotate-90">
            <circle cx="112" cy="112" r="100" fill="none" stroke={isDarkMode ? '#334155' : '#F1F5F9'} strokeWidth="14" />
            <circle
              cx="112" cy="112" r="100" fill="none" stroke={COLORS.GOLD} strokeWidth="14"
              strokeDasharray={2 * Math.PI * 100}
              strokeDashoffset={2 * Math.PI * 100 * (1 - count / 7)}
              strokeLinecap="round"
              className="transition-all duration-700 ease-out shadow-lg"
            />
          </svg>
          <div className="flex flex-col items-center z-10">
            <span className="text-8xl font-black mb-1" style={{ color: isDarkMode ? COLORS.WHITE : COLORS.BLACK }}>{count}</span>
            <span className={`text-xs font-black uppercase tracking-widest ${isDarkMode ? 'text-gray-400' : 'text-gray-400'}`}>
              {isAr ? 'أشواط مكتملة' : 'Laps Done'}
            </span>
          </div>
        </div>

        <p className="mt-8 text-lg font-black text-[#D4AF37]">
          {getLapText(count)}
        </p>

        <div className="mt-10 flex space-x-4 space-x-reverse w-full">
          <button
            onClick={increment}
            className="flex-1 py-5 bg-[#D4AF37] text-white rounded-[28px] font-black shadow-lg shadow-gold/20 tap-scale active:brightness-90 uppercase tracking-wider text-sm"
          >
            {isAr ? 'شوط جديد +' : 'Add Lap +'}
          </button>
          <button
            onClick={reset}
            className={`p-5 rounded-[28px] border-2 border-gray-100 flex items-center justify-center tap-scale ${isDarkMode ? 'bg-slate-700 border-slate-600 text-white' : 'bg-white text-slate-400 shadow-sm'}`}
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
          </button>
        </div>
      </div>

      <div className={`p-6 rounded-[32px] border ${isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-white border-gray-100'}`}>
         <h4 className="font-black text-[#D4AF37] mb-2">{isAr ? 'أذكار الطواف' : 'Tawaf Duas'}</h4>
         <p className={`text-sm leading-relaxed font-amiri text-lg ${isDarkMode ? 'text-gray-300' : 'text-gray-600'}`}>
            {TAWAF_DUAS[0].text}
         </p>
      </div>
    </div>
  );
};

export default TawafCounter;

import React, { useState } from 'react';
import { COLORS } from '../constants';

interface SaiCounterProps {
  language: 'en' | 'ar';
  isDarkMode: boolean;
}

const SaiCounter: React.FC<SaiCounterProps> = ({ language, isDarkMode }) => {
  const [laps, setLaps] = useState(0);
  const [direction, setDirection] = useState<'toMarwa' | 'toSafa'>('toMarwa');
  const isAr = language === 'ar';

  const increment = (newDir: 'toMarwa' | 'toSafa') => {
    if (laps < 7 && newDir !== direction) {
      setLaps(prev => prev + 1);
      setDirection(newDir);
    } else if (laps === 0 && newDir === 'toMarwa') {
      setLaps(1);
      setDirection('toMarwa');
    }
  };

  const reset = () => { setLaps(0); setDirection('toMarwa'); };

  return (
    <div className="px-6 py-4 space-y-6 animate-in slide-in-from-bottom-10 duration-500">
      <div className={`rounded-[48px] p-8 space-y-8 border-2 border-[#D4AF37]/20 ${isDarkMode ? 'bg-slate-800 shadow-black' : 'bg-white shadow-xl shadow-gold/5'}`}>
        <div className="flex justify-between items-center relative">
          <div className="flex flex-col items-center z-10">
            <div className={`w-14 h-14 rounded-3xl flex items-center justify-center transition-all duration-500 font-black ${direction === 'toSafa' || laps === 0 ? 'bg-[#D4AF37] text-white shadow-lg' : 'bg-gray-100 text-gray-400'}`}>
              S
            </div>
            <span className="mt-2 text-[10px] font-black uppercase text-gray-500">{isAr ? 'الصفا' : 'Safa'}</span>
          </div>
          <div className="flex-1 h-0.5 bg-gray-100 dark:bg-slate-700 mx-4 relative overflow-hidden">
             <div className="absolute inset-0 bg-[#D4AF37] transition-all duration-1000" style={{ width: `${(laps/7) * 100}%` }} />
          </div>
          <div className="flex flex-col items-center z-10">
            <div className={`w-14 h-14 rounded-3xl flex items-center justify-center transition-all duration-500 font-black ${direction === 'toMarwa' ? 'bg-[#D4AF37] text-white shadow-lg' : 'bg-gray-100 text-gray-400'}`}>
              M
            </div>
            <span className="mt-2 text-[10px] font-black uppercase text-gray-500">{isAr ? 'المروة' : 'Marwa'}</span>
          </div>
        </div>

        <div className="flex flex-col items-center justify-center py-4">
          <span className="text-8xl font-black text-[#D4AF37]">{laps}</span>
          <span className={`text-[10px] uppercase font-black tracking-[4px] mt-2 ${isDarkMode ? 'text-gray-400' : 'text-gray-400'}`}>
            {isAr ? 'أشواط السعي' : 'Sa’i Laps'}
          </span>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <button
            onClick={() => increment('toMarwa')}
            disabled={laps === 7 || direction === 'toMarwa' && laps > 0}
            className={`flex flex-col items-center p-6 rounded-3xl transition-all tap-scale border-2 ${direction === 'toSafa' || laps === 0 ? 'bg-[#D4AF37] border-[#D4AF37] text-white shadow-lg' : 'bg-gray-50 border-gray-50 text-gray-300'}`}
          >
            <svg className="w-8 h-8 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
            <span className="text-[10px] font-black uppercase tracking-wider">{isAr ? 'إلى المروة' : 'To Marwa'}</span>
          </button>
          <button
            onClick={() => increment('toSafa')}
            disabled={laps === 7 || direction === 'toSafa'}
            className={`flex flex-col items-center p-6 rounded-3xl transition-all tap-scale border-2 ${direction === 'toMarwa' ? 'bg-[#D4AF37] border-[#D4AF37] text-white shadow-lg' : 'bg-gray-50 border-gray-50 text-gray-300'}`}
          >
            <svg className="w-8 h-8 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            <span className="text-[10px] font-black uppercase tracking-wider">{isAr ? 'إلى الصفا' : 'To Safa'}</span>
          </button>
        </div>

        <button onClick={reset} className="w-full py-4 text-xs font-black text-gray-400 uppercase tracking-widest">{isAr ? 'إعادة العداد' : 'Reset Counter'}</button>
      </div>
    </div>
  );
};

export default SaiCounter;

import React, { useState, useRef, useEffect } from 'react';
import { askRitualAssistant } from '../services/geminiService';
import { AIMode } from '../types';
import { COLORS } from '../constants';

interface AIChatProps {
  language: 'en' | 'ar';
  isDarkMode: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ language, isDarkMode }) => {
  const [messages, setMessages] = useState<{role: 'user' | 'assistant', content: string}[]>([]);
  const [input, setInput] = useState('');
  const [mode, setMode] = useState<AIMode>(AIMode.FATWA);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isAr = language === 'ar';

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsLoading(true);

    const aiResponse = await askRitualAssistant(userMsg, mode, language);
    setMessages(prev => [...prev, { role: 'assistant', content: aiResponse }]);
    setIsLoading(false);
  };

  const ModeButton = ({ m, labelAr, labelEn }: { m: AIMode, labelAr: string, labelEn: string }) => (
    <button
      onClick={() => setMode(m)}
      className={`flex-1 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-wider transition-all border-2 ${mode === m ? 'bg-[#D4AF37] border-[#D4AF37] text-white' : isDarkMode ? 'bg-slate-800 border-slate-700 text-gray-400' : 'bg-white border-gray-100 text-gray-400'}`}
    >
      {isAr ? labelAr : labelEn}
    </button>
  );

  return (
    <div className={`flex flex-col h-full relative ${isDarkMode ? 'bg-slate-900' : 'bg-white'}`}>
      <div className={`p-4 border-b ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-gray-50 border-gray-100'}`}>
        <div className="flex space-x-2 space-x-reverse mb-4">
          <ModeButton m={AIMode.FATWA} labelAr="فتوى" labelEn="Fatwa" />
          <ModeButton m={AIMode.EXPLANATION} labelAr="شرح" labelEn="Guide" />
          <ModeButton m={AIMode.TRANSLATION} labelAr="ترجمة" labelEn="Translation" />
        </div>
        <div className="flex items-center space-x-3 space-x-reverse opacity-60">
           <svg className="w-4 h-4 text-[#D4AF37]" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
           <p className="text-[10px] font-black uppercase tracking-widest">{isAr ? 'موثوق من الرئاسة العامة' : 'Trusted Haramain Support'}</p>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-[28px] ${m.role === 'user' ? 'bg-[#D4AF37] text-white rounded-br-none shadow-lg shadow-gold/10' : isDarkMode ? 'bg-slate-800 text-gray-100 rounded-bl-none' : 'bg-gray-100 text-gray-800 rounded-bl-none shadow-sm'}`}>
              <p className="text-sm leading-relaxed">{m.content}</p>
            </div>
          </div>
        ))}
        {isLoading && <div className="animate-pulse flex space-x-2 p-4 bg-gray-50 dark:bg-slate-800 rounded-3xl w-24">
          <div className="w-2 h-2 bg-gold/50 rounded-full"></div>
          <div className="w-2 h-2 bg-gold/50 rounded-full"></div>
          <div className="w-2 h-2 bg-gold/50 rounded-full"></div>
        </div>}
      </div>

      <div className={`p-6 border-t ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-gray-100'}`}>
        <div className="flex space-x-2 space-x-reverse">
          <input
            value={input} onChange={(e) => setInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder={isAr ? 'اطرح سؤالك هنا...' : 'Ask your question...'}
            className={`flex-1 rounded-[24px] px-6 py-4 text-sm font-medium transition-all outline-none border-2 focus:border-[#D4AF37]/50 ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-gray-50 border-gray-50'}`}
          />
          <button onClick={handleSend} className="p-4 bg-[#D4AF37] text-white rounded-full shadow-xl tap-scale">
            <svg className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

