        </div>
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3 mb-4">
            <button onClick={() => setLanguage(Language.AR)} className={`py-4 rounded-3xl font-black text-xs uppercase tracking-wider transition-all border-2 ${language === Language.AR ? 'bg-[#D4AF37] border-[#D4AF37] text-white shadow-xl shadow-gold/20' : 'bg-gray-50 border-gray-100 text-gray-400'}`}>العربية</button>
            <button onClick={() => setLanguage(Language.EN)} className={`py-4 rounded-3xl font-black text-xs uppercase tracking-wider transition-all border-2 ${language === Language.EN ? 'bg-[#D4AF37] border-[#D4AF37] text-white shadow-xl shadow-gold/20' : 'bg-gray-50 border-gray-100 text-gray-400'}`}>English</button>
          </div>
          <button onClick={() => setOnboarded(true)} className="w-full py-5 bg-[#D4AF37] text-white rounded-[28px] font-black shadow-2xl shadow-gold/30 tap-scale uppercase tracking-widest text-sm">
            {isAr ? 'ابدأ الرحلة' : 'Begin Journey'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} language={language} isDarkMode={isDarkMode} toggleDarkMode={() => setIsDarkMode(!isDarkMode)}>
      {renderContent()}
    </Layout>
  );
};

