import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Home from './components/Home';
import TawafCounter from './components/TawafCounter';
import SaiCounter from './components/SaiCounter';
import AIChat from './components/AIChat';
import MapView from './components/MapView';
import { Language, LanguageNames, UserCategory, AccessibilityMode } from './types';
import { HOTELS, TOURISM } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [language, setLanguage] = useState<Language>(Language.AR);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [onboarded, setOnboarded] = useState(false);
  const [step, setStep] = useState(1);
  const [userName, setUserName] = useState('');
  const [userCategory, setUserCategory] = useState<UserCategory>(UserCategory.UMRAH_MAKKAH);
  const [accessibility, setAccessibility] = useState<AccessibilityMode>(AccessibilityMode.NORMAL);
  const [searchLang, setSearchLang] = useState('');

  const isAr = language === Language.AR;

  const filteredLanguages = Object.entries(LanguageNames).filter(([code, name]) => 
    name.toLowerCase().includes(searchLang.toLowerCase())
  );

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return <Home language={language} isDarkMode={isDarkMode} onAction={(action) => setActiveTab(action)} />;
      case 'tawaf':
      case 'rituals':
        return <TawafCounter language={language} isDarkMode={isDarkMode} />;
      case 'sai':
        return <SaiCounter language={language} isDarkMode={isDarkMode} />;
      case 'chat':
      case 'assistant':
        return <AIChat language={language} isDarkMode={isDarkMode} />;
      case 'map':
        return <MapView language={language} isDarkMode={isDarkMode} accessibility={accessibility} />;
      case 'hotels':
        return (
          <div className="px-6 py-4 space-y-6">
            <h3 className={`font-black text-xl mb-4 ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>{isAr ? 'فنادق قريبة' : 'Nearby Hotels'}</h3>
            {HOTELS.map(hotel => (
              <div key={hotel.id} className={`rounded-[32px] overflow-hidden border-2 border-gray-100 p-2 ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white'}`}>
                <img src={hotel.imageUrl} className="w-full h-44 object-cover rounded-[24px]" alt={hotel.name} />
                <div className="p-4 flex justify-between items-end">
                  <div>
                    <h4 className="font-black text-sm">{isAr ? hotel.nameAr : hotel.name}</h4>
                    <p className="text-xs text-gray-500 font-bold">{hotel.distance} {isAr ? 'من الحرم' : 'from Haram'}</p>
                  </div>
                  <button onClick={() => window.open(hotel.bookingUrl, '_blank')} className="bg-[#D4AF37] text-white px-6 py-2 rounded-xl text-xs font-black shadow-lg">
                    {isAr ? 'احجز الآن' : 'Book Now'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        );
      case 'tourism':
        return (
          <div className="px-6 py-4 space-y-6">
            <h3 className={`font-black text-xl mb-4 ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>{isAr ? 'استكشف مكة' : 'Explore Makkah'}</h3>
            {TOURISM.map(dest => (
              <div key={dest.id} className={`rounded-[40px] overflow-hidden relative h-64 shadow-xl mb-6`}>
                <img src={dest.imageUrl} className="absolute inset-0 w-full h-full object-cover" alt={dest.name} />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
                <div className="absolute bottom-6 left-6 right-6">
                  <h4 className="text-white font-black text-lg">{isAr ? dest.nameAr : dest.name}</h4>
                  <p className="text-white/80 text-xs font-medium mt-1">{isAr ? dest.descriptionAr : dest.description}</p>
                </div>
              </div>
            ))}
          </div>
        );
      default:
        return <Home language={language} isDarkMode={isDarkMode} onAction={(action) => setActiveTab(action)} />;
    }
  };

  const OnboardingStep = () => {
    switch (step) {
      case 1: // Language
        return (
          <div className="space-y-6 animate-in fade-in duration-500">
            <h2 className="text-2xl font-black">{isAr ? 'اختر لغتك' : 'Select Language'}</h2>
            <div className="relative">
              <input 
                type="text" 
                placeholder={isAr ? 'ابحث عن لغة...' : 'Search language...'}
                className="w-full p-4 bg-gray-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 ring-gold/20"
                value={searchLang}
                onChange={(e) => setSearchLang(e.target.value)}
              />
            </div>
            <div className="max-h-[300px] overflow-y-auto space-y-2 pr-2">
              {filteredLanguages.map(([code, name]) => (
                <button 
                  key={code}
                  onClick={() => { setLanguage(code as Language); setStep(2); }}
                  className={`w-full p-4 text-left rounded-2xl font-bold transition-all ${language === code ? 'bg-gold text-white' : 'bg-gray-50 dark:bg-slate-800 text-gray-500'}`}
                >
                  {name}
                </button>
              ))}
            </div>
          </div>
        );
      case 2: // Category
        return (
          <div className="space-y-6 animate-in slide-in-from-right duration-500">
            <h2 className="text-2xl font-black">{isAr ? 'من أنت؟' : 'Who are you?'}</h2>
            <div className="grid gap-4">
              {[
                { id: UserCategory.UMRAH_MAKKAH, label: isAr ? 'معتمر - مكة' : 'Umrah Performer - Makkah' },
                { id: UserCategory.HAJJ_MAKKAH, label: isAr ? 'حاج - مكة' : 'Hajj Performer - Makkah' },
                { id: UserCategory.VISITOR_MAKKAH, label: isAr ? 'زائر - مكة' : 'Visitor - Makkah' },
                { id: UserCategory.VISITOR_MADINAH, label: isAr ? 'زائر - المدينة' : 'Visitor - Madinah' },
              ].map(cat => (
                <button 
                  key={cat.id}
                  onClick={() => { setUserCategory(cat.id); setStep(3); }}
                  className="p-5 bg-gray-50 dark:bg-slate-800 rounded-3xl text-left font-black tap-scale hover:bg-gold/10"
                >
                  {cat.label}
                </button>
              ))}
            </div>
          </div>
        );
      case 3: // Name
        return (
          <div className="space-y-6 animate-in slide-in-from-right duration-500">
            <h2 className="text-2xl font-black">{isAr ? 'ماذا ناديك؟' : 'What is your name?'}</h2>
            <p className="text-gray-500 font-bold">{isAr ? 'اختياري. كيف تود أن نناديك؟' : 'Optional. What should we call you?'}</p>
            <input 
              type="text" 
              className="w-full p-5 bg-gray-50 dark:bg-slate-800 rounded-3xl outline-none border-2 focus:border-gold"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              placeholder={isAr ? 'الاسم المستعار...' : 'Your name...'}
            />
            <button 
              onClick={() => setStep(4)}
              className="w-full p-5 bg-gold text-white rounded-3xl font-black shadow-xl"
            >
              {isAr ? 'التالي' : 'Next'}
            </button>
          </div>
        );
      case 4: // Accessibility
        return (
          <div className="space-y-6 animate-in slide-in-from-right duration-500">
            <h2 className="text-2xl font-black">{isAr ? 'احتياجات الوصول' : 'Accessibility Options'}</h2>
            <div className="grid gap-4">
              {[
                { id: AccessibilityMode.NORMAL, label: isAr ? 'لا يوجد احتياجات خاصة' : 'No specific needs' },
                { id: AccessibilityMode.VISUAL, label: isAr ? 'ضعف بصر' : 'Visually Impaired' },
                { id: AccessibilityMode.WHEELCHAIR, label: isAr ? 'مستخدم كرسي متحرك' : 'Wheelchair User' },
                { id: AccessibilityMode.HEARING, label: isAr ? 'ضعف سمع' : 'Hearing Impaired' },
              ].map(acc => (
                <button 
                  key={acc.id}
                  onClick={() => { setAccessibility(acc.id); setOnboarded(true); }}
                  className="p-5 bg-gray-50 dark:bg-slate-800 rounded-3xl text-left font-black tap-scale hover:bg-gold/10"
                >
                  {acc.label}
                </button>
              ))}
            </div>
          </div>
        );
      default: return null;
    }
  };

  if (!onboarded) {
    return (
      <div className={`flex flex-col h-screen p-10 justify-between ${isDarkMode ? 'bg-slate-900 text-white' : 'bg-white'}`}>
        <div className="flex justify-end pt-4">
           <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-3 bg-gray-100 dark:bg-slate-800 rounded-2xl">
              {isDarkMode ? '☀️' : '🌙'}
           </button>
        </div>
        <OnboardingStep />
        <div className="flex justify-center pb-8">
           <div className="flex space-x-1">
              {[1,2,3,4].map(s => (
                <div key={s} className={`h-1.5 rounded-full transition-all ${step === s ? 'w-8 bg-gold' : 'w-2 bg-gray-200'}`} />
              ))}
           </div>
        </div>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} language={language} isDarkMode={isDarkMode} toggleDarkMode={() => setIsDarkMode(!isDarkMode)}>
      {renderContent()}
    </Layout>
  );
};

export default App;

