  const [direction, setDirection] = useState<'toMarwa' | 'toSafa'>('toMarwa');
  const isAr = language === 'ar';

  const increment = (newDir: 'toMarwa' | 'toSafa') => {
    if (laps < 7 && newDir !== direction) {
      setLaps(prev => prev + 1);
      setDirection(newDir);
    } else if (laps === 0 && newDir === 'toMarwa') {
      setLaps(1);
      setDirection('toMarwa');
    }
  };

  const reset = () => { setLaps(0); setDirection('toMarwa'); };

  return (
    <div className="px-6 py-4 space-y-6 animate-in slide-in-from-bottom-10 duration-500">
      <div className={`rounded-[48px] p-10 space-y-10 border-2 border-[#D4AF37]/20 transition-all ${isDarkMode ? 'bg-slate-800 shadow-2xl' : 'bg-white shadow-2xl shadow-gold/5'}`}>
        <div className="flex justify-between items-center relative">
          <div className="flex flex-col items-center z-10">
            <div className={`w-16 h-16 rounded-[24px] flex items-center justify-center transition-all duration-500 font-black text-lg ${direction === 'toSafa' || laps === 0 ? 'bg-[#D4AF37] text-white shadow-xl' : 'bg-gray-100 dark:bg-slate-700 text-gray-400'}`}>
              S
            </div>
            <span className="mt-2 text-[11px] font-black uppercase text-gray-500">{isAr ? 'الصفا' : 'Safa'}</span>
          </div>
          <div className="flex-1 h-1 bg-gray-100 dark:bg-slate-700 mx-6 rounded-full relative overflow-hidden">
             <div className="absolute inset-0 bg-[#D4AF37] transition-all duration-1000" style={{ width: `${(laps/7) * 100}%` }} />
          </div>
          <div className="flex flex-col items-center z-10">
            <div className={`w-16 h-16 rounded-[24px] flex items-center justify-center transition-all duration-500 font-black text-lg ${direction === 'toMarwa' ? 'bg-[#D4AF37] text-white shadow-xl' : 'bg-gray-100 dark:bg-slate-700 text-gray-400'}`}>
              M
            </div>
            <span className="mt-2 text-[11px] font-black uppercase text-gray-500">{isAr ? 'المروة' : 'Marwa'}</span>
          </div>
        </div>

        <div className="flex flex-col items-center justify-center py-2">
          <span className="text-8xl font-black text-[#D4AF37]">{laps}</span>
          <span className={`text-[10px] uppercase font-black tracking-[5px] mt-2 ${isDarkMode ? 'text-gray-400' : 'text-gray-400'}`}>
            {isAr ? 'أشواط السعي' : 'Sa’i Laps'}
          </span>
        </div>

        <div className="grid grid-cols-2 gap-5">
          <button
            onClick={() => increment('toMarwa')}
            disabled={laps === 7 || (direction === 'toMarwa' && laps > 0)}
            className={`flex flex-col items-center p-8 rounded-[32px] transition-all tap-scale border-2 ${direction === 'toSafa' || laps === 0 ? 'bg-[#D4AF37] border-[#D4AF37] text-white shadow-2xl shadow-gold/20' : 'bg-gray-50 dark:bg-slate-700 border-gray-50 dark:border-slate-700 text-gray-300'}`}
          >
            <svg className="w-8 h-8 mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
            <span className="text-[10px] font-black uppercase tracking-wider">{isAr ? 'إلى المروة' : 'To Marwa'}</span>
          </button>
          <button
            onClick={() => increment('toSafa')}
            disabled={laps === 7 || direction === 'toSafa'}
            className={`flex flex-col items-center p-8 rounded-[32px] transition-all tap-scale border-2 ${direction === 'toMarwa' ? 'bg-[#D4AF37] border-[#D4AF37] text-white shadow-2xl shadow-gold/20' : 'bg-gray-50 dark:bg-slate-700 border-gray-50 dark:border-slate-700 text-gray-300'}`}
          >
            <svg className="w-8 h-8 mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            <span className="text-[10px] font-black uppercase tracking-wider">{isAr ? 'إلى الصفا' : 'To Safa'}</span>
          </button>
        </div>

        <button onClick={reset} className="w-full py-4 text-[10px] font-black text-gray-400 uppercase tracking-[4px] tap-scale">{isAr ? 'إعادة العداد' : 'Reset Counter'}</button>
      </div>
    </div>
  );
};

export default SaiCounter;

import React, { useState, useRef, useEffect } from 'react';
import { askRitualAssistant } from '../services/geminiService';
import { AIMode } from '../types';
import { COLORS } from '../constants';

interface AIChatProps {
  language: string;
  isDarkMode: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ language, isDarkMode }) => {
  const [messages, setMessages] = useState<{role: 'user' | 'assistant', content: string}[]>([]);
  const [input, setInput] = useState('');
  const [mode, setMode] = useState<AIMode>(AIMode.FATWA);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isAr = language === 'ar';

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsLoading(true);

    const aiResponse = await askRitualAssistant(userMsg, mode, language);
    setMessages(prev => [...prev, { role: 'assistant', content: aiResponse }]);
    setIsLoading(false);
  };

  const ModeButton = ({ m, labelAr, labelEn }: { m: AIMode, labelAr: string, labelEn: string }) => (
    <button
      onClick={() => setMode(m)}
      className={`flex-1 py-3.5 rounded-[20px] text-[11px] font-black uppercase tracking-widest transition-all border-2 ${mode === m ? 'bg-[#D4AF37] border-[#D4AF37] text-white shadow-lg shadow-gold/20' : isDarkMode ? 'bg-slate-800 border-slate-700 text-gray-500' : 'bg-white border-gray-100 text-gray-400'}`}
    >
      {isAr ? labelAr : labelEn}
    </button>
  );

  return (
    <div className={`flex flex-col h-full relative transition-colors duration-500 ${isDarkMode ? 'bg-slate-900' : 'bg-white'}`}>
      <div className={`p-6 border-b ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-gray-50 border-gray-100 shadow-sm'}`}>
        <div className="flex space-x-3 space-x-reverse mb-5">
          <ModeButton m={AIMode.FATWA} labelAr="فتوى" labelEn="Fatwa" />
          <ModeButton m={AIMode.EXPLANATION} labelAr="شرح" labelEn="Guide" />
          <ModeButton m={AIMode.TRANSLATION} labelAr="ترجمة" labelEn="Translate" />
        </div>
        <div className="flex items-center space-x-3 space-x-reverse opacity-50 px-2">
           <svg className="w-4 h-4 text-[#D4AF37]" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
           <p className="text-[10px] font-black uppercase tracking-widest">{isAr ? 'موثوق من الرئاسة العامة' : 'Official Content Source'}</p>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-6">
        {messages.length === 0 && (
           <div className="flex flex-col items-center justify-center h-full text-center opacity-30 space-y-4">
              <div className="w-16 h-16 rounded-full border-2 border-dashed border-gold flex items-center justify-center">
                 <svg className="w-8 h-8 text-gold" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              </div>
              <p className="text-xs font-black uppercase tracking-[3px]">{isAr ? 'ابدأ المحادثة' : 'Start Chatting'}</p>
           </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-5 rounded-[32px] ${m.role === 'user' ? 'bg-[#D4AF37] text-white rounded-br-none shadow-xl shadow-gold/10' : isDarkMode ? 'bg-slate-800 text-gray-100 rounded-bl-none border border-slate-700' : 'bg-gray-100 text-gray-800 rounded-bl-none shadow-sm'}`}>
              <p className="text-sm leading-relaxed font-medium">{m.content}</p>
            </div>
          </div>
        ))}
        {isLoading && <div className="animate-pulse flex space-x-2 p-5 bg-gray-50 dark:bg-slate-800 rounded-[32px] w-24 border border-gray-100 dark:border-slate-700">
          <div className="w-2 h-2 bg-gold/50 rounded-full"></div>
          <div className="w-2 h-2 bg-gold/50 rounded-full"></div>
          <div className="w-2 h-2 bg-gold/50 rounded-full"></div>
        </div>}
      </div>

      <div className={`p-6 border-t ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-gray-100 shadow-[0_-4px_30px_rgba(0,0,0,0.02)]'}`}>
        <div className="flex space-x-3 space-x-reverse items-center">
          <input
            value={input} onChange={(e) => setInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder={isAr ? 'تفضل بسؤالك...' : 'How can I assist you?'}
            className={`flex-1 rounded-[28px] px-7 py-4.5 text-sm font-bold transition-all outline-none border-2 focus:border-[#D4AF37]/50 ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-gray-50 border-gray-50'}`}
          />
          <button onClick={handleSend} className="p-4.5 bg-[#D4AF37] text-white rounded-full shadow-2xl tap-scale active:scale-90 transition-all">
            <svg className={`w-6 h-6 ${isAr ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

