import React, { useState } from 'react';
import { COLORS, TAWAF_DUAS } from '../constants';

interface TawafCounterProps {
  language: string;
  isDarkMode: boolean;
}

const TawafCounter: React.FC<TawafCounterProps> = ({ language, isDarkMode }) => {
  const [count, setCount] = useState(0);
  const isAr = language === 'ar';

  const getLapText = (c: number) => {
    if (!isAr) return `Lap ${c} of 7`;
    const texts = ['', 'الأول', 'الثاني', 'الثالث', 'الرابع', 'الخامس', 'السادس', 'السابع'];
    return c > 0 ? `الشوط ${texts[c]}` : 'ابدأ الطواف';
  };

  const increment = () => { if (count < 7) setCount(prev => prev + 1); };
  const reset = () => setCount(0);

  return (
    <div className="px-6 py-4 space-y-6 animate-in slide-in-from-bottom-10 duration-500">
      <div className={`relative flex flex-col items-center justify-center p-12 rounded-[48px] border-2 border-[#D4AF37]/20 transition-all ${isDarkMode ? 'bg-slate-800' : 'bg-white shadow-2xl shadow-gold/5'}`}>
        <div className="relative w-56 h-56 flex items-center justify-center">
          <svg className="absolute w-full h-full -rotate-90">
            <circle cx="112" cy="112" r="100" fill="none" stroke={isDarkMode ? '#334155' : '#F1F5F9'} strokeWidth="16" />
            <circle
              cx="112" cy="112" r="100" fill="none" stroke={COLORS.GOLD} strokeWidth="16"
              strokeDasharray={2 * Math.PI * 100}
              strokeDashoffset={2 * Math.PI * 100 * (1 - count / 7)}
              strokeLinecap="round"
              className="transition-all duration-700 ease-out"
            />
          </svg>
          <div className="flex flex-col items-center z-10">
            <span className="text-8xl font-black mb-1" style={{ color: isDarkMode ? COLORS.WHITE : COLORS.BLACK }}>{count}</span>
            <span className={`text-[10px] font-black uppercase tracking-[3px] ${isDarkMode ? 'text-gray-400' : 'text-gray-400'}`}>
              {isAr ? 'أشواط' : 'Laps'}
            </span>
          </div>
        </div>

        <p className="mt-8 text-xl font-black text-[#D4AF37]">
          {getLapText(count)}
        </p>

        <div className="mt-10 flex space-x-4 space-x-reverse w-full">
          <button
            onClick={increment}
            className="flex-1 py-5 bg-[#D4AF37] text-white rounded-[32px] font-black shadow-xl shadow-gold/20 tap-scale active:brightness-90 uppercase tracking-widest text-xs"
          >
            {isAr ? 'شوط جديد +' : 'Add Lap +'}
          </button>
          <button
            onClick={reset}
            className={`p-5 rounded-[32px] border-2 border-gray-100 flex items-center justify-center tap-scale ${isDarkMode ? 'bg-slate-700 border-slate-600 text-white shadow-sm' : 'bg-white text-slate-400 shadow-md'}`}
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>
          </button>
        </div>
      </div>

      <div className={`p-8 rounded-[40px] border shadow-sm ${isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-white border-gray-100'}`}>
         <div className="flex items-center space-x-3 space-x-reverse mb-3">
           <div className="w-8 h-8 rounded-full bg-gold/10 flex items-center justify-center">
              <svg className="w-4 h-4 text-gold" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
           </div>
           <h4 className="font-black text-sm text-slate-800 dark:text-white">{isAr ? 'أذكار الطواف' : 'Tawaf Duas'}</h4>
         </div>
         <p className={`leading-relaxed font-amiri text-xl ${isDarkMode ? 'text-gray-300' : 'text-gray-700'}`}>
            {TAWAF_DUAS[0].text}
         </p>
      </div>
    </div>
  );
};

export default TawafCounter;

