// Removed unused imports HOTELS and TOURISM which were causing errors as they are not exported from types.ts
import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Home from './components/Home';
import TawafCounter from './components/TawafCounter';
import SaiCounter from './components/SaiCounter';
import AIChat from './components/AIChat';
import MapView from './components/MapView';
import { Language, LanguageNames, UserCategory, AccessibilityMode } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [language, setLanguage] = useState<Language>(Language.AR);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [onboarded, setOnboarded] = useState(false);
  const [step, setStep] = useState(1);
  const [userName, setUserName] = useState('');
  const [userCategory, setUserCategory] = useState<UserCategory>(UserCategory.UMRAH_MAKKAH);
  const [accessibility, setAccessibility] = useState<AccessibilityMode>(AccessibilityMode.NORMAL);
  const [searchLang, setSearchLang] = useState('');

  const isAr = language === Language.AR;

  const filteredLanguages = Object.entries(LanguageNames).filter(([code, name]) => 
    name.toLowerCase().includes(searchLang.toLowerCase())
  );

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return <Home language={language} isDarkMode={isDarkMode} onAction={(action) => setActiveTab(action)} />;
      case 'tawaf':
      case 'rituals':
        return <TawafCounter language={language} isDarkMode={isDarkMode} />;
      case 'sai':
        return <SaiCounter language={language} isDarkMode={isDarkMode} />;
      case 'chat':
      case 'assistant':
        return <AIChat language={language} isDarkMode={isDarkMode} />;
      case 'map':
        return <MapView language={language} isDarkMode={isDarkMode} accessibility={accessibility} />;
      case 'hotels':
        return (
          <div className="px-6 py-6 space-y-8 animate-in fade-in duration-500">
            <h3 className={`font-black text-xl mb-6 ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>{isAr ? 'فنادق قريبة من الحرم' : 'Hotels Near Haram'}</h3>
            <div className="grid gap-8">
              {/* Mock Hotels Data from types/constants handled locally */}
              {[
                { name: 'فيرمونت برج الساعة', nameEn: 'Fairmont Clock Tower', dist: '50m', img: 'https://cf.bstatic.com/xdata/images/hotel/max1024x768/29267232.jpg?k=7a2e5d99', link: 'https://www.booking.com/hotel/sa/makkah-clock-royal-tower-a-fairmont.html' },
                { name: 'رافلز مكة بالاس', nameEn: 'Raffles Makkah Palace', dist: '100m', img: 'https://cf.bstatic.com/xdata/images/hotel/max1024x768/11883100.jpg?k=7a2e5d99', link: 'https://www.booking.com/hotel/sa/raffles-makkah-palace.html' }
              ].map((hotel, i) => (
                <div key={i} className={`rounded-[48px] overflow-hidden border-2 transition-all p-2.5 ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-100 shadow-2xl shadow-gold/5'}`}>
                  <img src={hotel.img} className="w-full h-52 object-cover rounded-[40px] shadow-sm" alt={hotel.name} />
                  <div className="p-6 flex justify-between items-center">
                    <div>
                      <h4 className="font-black text-sm">{isAr ? hotel.name : hotel.nameEn}</h4>
                      <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mt-1">{hotel.dist} {isAr ? 'من ساحات الحرم' : 'from Haram'}</p>
                    </div>
                    <button onClick={() => window.open(hotel.link, '_blank')} className="bg-[#D4AF37] text-white px-7 py-3 rounded-2xl text-[10px] font-black shadow-xl uppercase tracking-widest tap-scale">
                      {isAr ? 'احجز الآن' : 'Book'}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'tourism':
        return (
          <div className="px-6 py-6 space-y-8 animate-in fade-in duration-500">
            <h3 className={`font-black text-xl mb-6 ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>{isAr ? 'اكتشف مكة المكرمة' : 'Discover Makkah'}</h3>
            {[
               { name: 'غار حراء', nameEn: 'Hira Cave', img: 'https://images.unsplash.com/photo-1589118949245-7d38baf380d6?q=80&w=800', desc: 'مكان نزول الوحي الأول', descEn: 'Where revelation first began' },
               { name: 'متحف مكة', nameEn: 'Makkah Museum', img: 'https://images.unsplash.com/photo-1565154060049-366978430a6f?q=80&w=800', desc: 'تاريخ العاصمة المقدسة عبر العصور', descEn: 'Holy City history through ages' }
            ].map((dest, i) => (
              <div key={i} className={`rounded-[56px] overflow-hidden relative h-72 shadow-2xl mb-8 group tap-scale border-2 border-gold/10`}>
                <img src={dest.img} className="absolute inset-0 w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" alt={dest.name} />
                <div className="absolute inset-0 bg-gradient-to-t from-black/95 via-black/20 to-transparent"></div>
                <div className="absolute bottom-8 left-8 right-8">
                  <h4 className="text-white font-black text-xl tracking-tight">{isAr ? dest.name : dest.nameEn}</h4>
                  <p className="text-white/80 text-[11px] font-bold mt-2 uppercase tracking-[2px] opacity-90">{isAr ? dest.desc : dest.descEn}</p>
                </div>
              </div>
            ))}
          </div>
        );
      default:
        return <Home language={language} isDarkMode={isDarkMode} onAction={(action) => setActiveTab(action)} />;
    }
  };

  const OnboardingStep = () => {
    switch (step) {
      case 1: // Language Select (20 Languages)
        return (
          <div className="space-y-8 animate-in fade-in duration-700">
            <h2 className="text-3xl font-black tracking-tight">{isAr ? 'اختر لغة التطبيق' : 'Select Language'}</h2>
            <div className="relative">
              <input 
                type="text" 
                placeholder={isAr ? 'ابحث عن لغتك...' : 'Search for your language...'}
                className="w-full p-5 bg-gray-50 dark:bg-slate-800 rounded-[28px] outline-none border-2 border-transparent focus:border-gold/30 transition-all font-bold text-sm shadow-sm"
                value={searchLang}
                onChange={(e) => setSearchLang(e.target.value)}
              />
            </div>
            <div className="max-h-[360px] overflow-y-auto space-y-3 pr-2 scrollbar-hide">
              {filteredLanguages.map(([code, name]) => (
                <button 
                  key={code}
                  onClick={() => { setLanguage(code as Language); setStep(2); }}
                  className={`w-full p-5 text-left rounded-[28px] font-black text-sm tracking-tight transition-all border-2 ${language === code ? 'bg-gold border-gold text-white shadow-xl shadow-gold/20' : 'bg-gray-50 dark:bg-slate-800 border-gray-100 dark:border-slate-800 text-gray-400'}`}
                >
                  {name}
                </button>
              ))}
            </div>
          </div>
        );
      case 2: // User Category
        return (
          <div className="space-y-8 animate-in slide-in-from-right duration-700">
            <h2 className="text-3xl font-black tracking-tight">{isAr ? 'الغرض من الزيارة' : 'Purpose of Visit'}</h2>
            <div className="grid gap-5">
              {[
                { id: UserCategory.UMRAH_MAKKAH, label: isAr ? 'أداء مناسك العمرة' : 'Performing Umrah' },
                { id: UserCategory.HAJJ_MAKKAH, label: isAr ? 'أداء مناسك الحج' : 'Performing Hajj' },
                { id: UserCategory.VISITOR_MAKKAH, label: isAr ? 'زيارة مكة المكرمة' : 'Visiting Makkah' },
                { id: UserCategory.VISITOR_MADINAH, label: isAr ? 'زيارة المدينة المنورة' : 'Visiting Madinah' },
              ].map(cat => (
                <button 
                  key={cat.id}
                  onClick={() => { setUserCategory(cat.id); setStep(3); }}
                  className="p-6 bg-gray-50 dark:bg-slate-800 rounded-[32px] text-left font-black tracking-tight tap-scale border-2 border-transparent hover:border-gold/20 text-sm"
                >
                  {cat.label}
                </button>
              ))}
            </div>
          </div>
        );
      case 3: // Noble Name
        return (
          <div className="space-y-8 animate-in slide-in-from-right duration-700">
            <h2 className="text-3xl font-black tracking-tight">{isAr ? 'ما هو اسمك الكريم؟' : 'May we know your name?'}</h2>
            <p className="text-gray-500 font-bold opacity-80">{isAr ? 'اختياري. يسعدنا أن نعرف كيف نناديك' : 'Optional. We would love to know how to call you.'}</p>
            <input 
              type="text" 
              className="w-full p-6 bg-gray-50 dark:bg-slate-800 rounded-[32px] outline-none border-2 border-transparent focus:border-gold transition-all font-black text-lg"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              placeholder={isAr ? 'الاسم الكريم...' : 'Your noble name...'}
            />
            <button 
              onClick={() => setStep(4)}
              className="w-full p-6 bg-gold text-white rounded-[32px] font-black shadow-2xl shadow-gold/30 tap-scale uppercase tracking-[3px] text-xs"
            >
              {isAr ? 'استمرار' : 'Continue'}
            </button>
          </div>
        );
      case 4: // Accessibility
        return (
          <div className="space-y-8 animate-in slide-in-from-right duration-700">
            <h2 className="text-3xl font-black tracking-tight">{isAr ? 'احتياجات الوصول' : 'Accessibility Preferences'}</h2>
            <div className="grid gap-5">
              {[
                { id: AccessibilityMode.NORMAL, label: isAr ? 'لا توجد احتياجات خاصة' : 'No specific needs' },
                { id: AccessibilityMode.VISUAL, label: isAr ? 'ضعاف البصر (توجيه صوتي)' : 'Visual Impairment (Voice)' },
                { id: AccessibilityMode.WHEELCHAIR, label: isAr ? 'مستخدمي الكراسي (طرق مستوية)' : 'Wheelchair (Level Routes)' },
                { id: AccessibilityMode.HEARING, label: isAr ? 'ضعاف السمع (تنبيهات نصية)' : 'Hearing Impairment (Text)' },
              ].map(acc => (
                <button 
                  key={acc.id}
                  onClick={() => { setAccessibility(acc.id); setOnboarded(true); }}
                  className="p-6 bg-gray-50 dark:bg-slate-800 rounded-[32px] text-left font-black tracking-tight tap-scale border-2 border-transparent hover:border-gold/20 text-sm"
                >
                  {acc.label}
                </button>
              ))}
            </div>
          </div>
        );
      default: return null;
    }
  };

  if (!onboarded) {
    return (
      <div className={`flex flex-col h-screen p-12 justify-between transition-colors duration-1000 ${isDarkMode ? 'bg-slate-900 text-white' : 'bg-white'}`}>
        <div className="flex justify-between items-center pt-6">
           <div className="w-10 h-10 bg-gold/5 rounded-2xl flex items-center justify-center border border-gold/10">
              <svg className="w-5 h-5 text-gold" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
           </div>
           <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-3.5 bg-gray-100 dark:bg-slate-800 rounded-2xl shadow-sm transition-all tap-scale">
              {isDarkMode ? '☀️' : '🌙'}
           </button>
        </div>
        <div className="flex-1 flex flex-col justify-center">
          <OnboardingStep />
        </div>
        <div className="flex justify-center pb-10">
           <div className="flex space-x-1.5 space-x-reverse">
              {[1,2,3,4].map(s => (
                <div key={s} className={`h-1.5 rounded-full transition-all duration-500 ${step === s ? 'w-10 bg-gold' : 'w-2 bg-gray-200 dark:bg-slate-800'}`} />
              ))}
           </div>
        </div>
      </div>
    );
  }

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} language={language} isDarkMode={isDarkMode} toggleDarkMode={() => setIsDarkMode(!isDarkMode)}>
      {renderContent()}
    </Layout>
  );
};

