import React, { useState, useRef, useEffect } from 'react';
import { askRitualAssistant } from '../services/geminiService';
import { AIMode, Language } from '../types';
import { COLORS } from '../constants';

interface AIChatProps {
  language: string;
  isDarkMode: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ language, isDarkMode }) => {
  const [messages, setMessages] = useState<{role: 'user' | 'assistant', content: string, time: string}[]>([
    {
      role: 'assistant',
      content: 'Assalamu Alaikum! I am Rafeeq, your dedicated spiritual companion. How can I assist you with your faith, practice, or learning today?',
      time: '09:41 AM'
    }
  ]);
  const [input, setInput] = useState('');
  const [mode, setMode] = useState<AIMode>(AIMode.FATWA);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isAr = language === 'ar';

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const now = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg, time: now }]);
    setIsLoading(true);

    const aiResponse = await askRitualAssistant(userMsg, mode, language);
    setMessages(prev => [...prev, { role: 'assistant', content: aiResponse, time: now }]);
    setIsLoading(false);
  };

  const suggestions = [
    { label: isAr ? 'أوقات الصلاة' : 'Prayer Times', icon: 'schedule' },
    { label: isAr ? 'اتجاه القبلة' : 'Qibla Direction', icon: 'explore' },
