            <span className="material-symbols-outlined text-[14px] text-[#5D4037] dark:text-orange-200">signal_cellular_alt</span>
            <span className="material-symbols-outlined text-[14px] text-[#5D4037] dark:text-orange-200">wifi</span>
            <span className="material-symbols-outlined text-[14px] text-[#5D4037] dark:text-orange-200">battery_full</span>
          </div>
        </div>

        <header className="px-8 py-4 flex flex-col items-center">
