            <h2 className="text-2xl font-extrabold text-[#5D4037] dark:text-white">{t.setupTitle}</h2>
            <p className="text-[#5D4037]/70 dark:text-white/60 text-sm mt-2 leading-relaxed">{t.setupDesc}</p>
          </div>

          <div className="flex flex-col gap-6">
            <div className="flex flex-col gap-2">
              <label className="text-[10px] font-bold text-[#5D4037] dark:text-orange-200 uppercase tracking-widest px-1">{t.langLabel}</label>
              <div className="relative">
                <select 
                  value={language}
                  onChange={(e) => setLanguage(e.target.value as Language)}
                  className="w-full p-4 pr-12 bg-white dark:bg-zinc-800 border-2 border-[#5D4037] rounded-2xl font-semibold outline-none focus:ring-0 appearance-none text-[#5D4037] dark:text-white"
                >
                  <option value={Language.AR}>العربية (Arabic)</option>
                  <option value={Language.EN}>English</option>
                  <option value={Language.UR}>اردو (Urdu)</option>
                  <option value={Language.ID}>Bahasa Indonesia</option>
                  <option value={Language.TR}>Türkçe</option>
                  <option value={Language.FR}>Français</option>
                </select>
                <div className={`absolute ${isAr ? 'left-4' : 'right-4'} top-1/2 -translate-y-1/2 pointer-events-none`}>
                  <svg className="w-6 h-6 text-[#C59E39]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" />
                  </svg>
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-2">
              <label className="text-[10px] font-bold text-[#5D4037] dark:text-orange-200 uppercase tracking-widest px-1">{t.accLabel}</label>
              <div className="relative">
                <select 
                  value={accessibility}
                  onChange={(e) => setAccessibility(e.target.value as AccessibilityMode)}
                  className="w-full p-4 pr-12 bg-white dark:bg-zinc-800 border-2 border-[#5D4037] rounded-2xl font-semibold outline-none focus:ring-0 appearance-none text-[#5D4037] dark:text-white"
                >
                  <option value={AccessibilityMode.NORMAL}>{isAr ? 'لا يوجد / لا ينطبق' : 'None / Not Applicable'}</option>
                  <option value={AccessibilityMode.VISUAL}>{isAr ? 'إعاقة بصرية' : 'Visual Impairment'}</option>
                  <option value={AccessibilityMode.HEARING}>{isAr ? 'إعاقة سمعية' : 'Hearing Impairment'}</option>
                  <option value={AccessibilityMode.WHEELCHAIR}>{isAr ? 'إعاقة حركية' : 'Motor Impairment'}</option>
                </select>
                <div className={`absolute ${isAr ? 'left-4' : 'right-4'} top-1/2 -translate-y-1/2 pointer-events-none`}>
                  <svg className="w-6 h-6 text-[#C59E39]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" />
