                >
                  <option value="">{isAr ? 'اختر بلدك' : 'Select Your Country'}</option>
                  <option value="sa">{isAr ? 'المملكة العربية السعودية' : 'Saudi Arabia'}</option>
                  <option value="pk">{isAr ? 'باكستان' : 'Pakistan'}</option>
                  <option value="my">{isAr ? 'ماليزيا' : 'Malaysia'}</option>
                  <option value="id">{isAr ? 'إندونيسيا' : 'Indonesia'}</option>
                  <option value="eg">{isAr ? 'مصر' : 'Egypt'}</option>
                  <option value="in">{isAr ? 'الهند' : 'India'}</option>
                </select>
                <div className={`absolute ${isAr ? 'left-4' : 'right-4'} top-1/2 -translate-y-1/2 pointer-events-none`}>
                  <svg className="w-6 h-6 text-[#C59E39]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
