      {activeTab === id && <div className="size-1 bg-[#C59E39] rounded-full mt-0.5 animate-pulse"></div>}
    </button>
  );

  return (
    <div className={`flex flex-col h-screen transition-colors duration-500 ${isDarkMode ? 'bg-[#2D241E] text-white' : 'bg-[#FAF3E0] text-[#2B1B17]'} ${isAr ? 'rtl' : 'ltr'}`} dir={isAr ? 'rtl' : 'ltr'}>
      <header className={`px-6 py-4 flex items-center justify-between shrink-0 shadow-lg z-50 bg-[#5D4037] text-white`}>
