          <div className="size-10 bg-[#C59E39]/20 rounded-full flex items-center justify-center border border-[#C59E39]/30">
            <span className="material-symbols-outlined text-[#C59E39]">mosque</span>
          </div>
          <div>
            <h1 className="text-lg font-bold leading-none tracking-tight font-amiri">
              {isAr ? 'رفيق' : 'Rafeeq'}
