      <nav className={`fixed bottom-0 left-0 right-0 bg-white dark:bg-[#2D241E] border-t border-gray-100 dark:border-zinc-800 py-3 px-6 flex justify-between items-center z-[100] shadow-[0_-4px_20px_rgba(0,0,0,0.05)]`}>
