import React, { useState, useRef, useEffect } from 'react';
import { askRitualAssistant } from '../services/geminiService';
import { AIMode, Language } from '../types';

interface AIChatProps {
  language: string;
  isDarkMode: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ language, isDarkMode }) => {
  const isAr = language === 'ar';

  const initialMsg = isAr 
    ? 'السلام عليكم! أنا رفيق، رفيقك الروحاني المخصص. كيف يمكنني مساعدتك في رحلتك الإيمانية اليوم؟' 
    : 'Assalamu Alaikum! I am Rafeeq, your dedicated spiritual companion. How can I assist you with your faith, practice, or learning today?';

  const [messages, setMessages] = useState<{role: 'user' | 'assistant', content: string, time: string}[]>([
    { role: 'assistant', content: initialMsg, time: '09:41 AM' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const now = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg, time: now }]);
    setIsLoading(true);

    const aiResponse = await askRitualAssistant(userMsg, AIMode.FATWA, language);
    setMessages(prev => [...prev, { role: 'assistant', content: aiResponse, time: now }]);
    setIsLoading(false);
  };

  const labels = {
    placeholder: isAr ? 'اسأل أي شيء عن الدين...' : 'Ask anything about Deen...',
    copy: isAr ? 'نسخ' : 'Copy',
    share: isAr ? 'مشاركة' : 'Share',
    guideTitle: isAr ? 'دليل روحاني' : 'Spiritual Guide'
  };

  const suggestions = [
    { label: isAr ? 'أوقات الصلاة' : 'Prayer Times', icon: 'schedule' },
    { label: isAr ? 'اتجاه القبلة' : 'Qibla Direction', icon: 'explore' },
    { label: isAr ? 'أذكار اليوم' : 'Daily Azkar', icon: 'menu_book' }
  ];

  return (
    <div className={`flex flex-col h-full ${isDarkMode ? 'bg-[#1F1715]' : 'bg-[#FAF3E0]'}`}>
      {/* Suggestions Header */}
      <div className={`p-4 border-b overflow-x-auto scrollbar-hide flex gap-2 ${isDarkMode ? 'bg-[#2D221F] border-white/5' : 'bg-white/50 border-gray-100'}`}>
        {suggestions.map((s, idx) => (
          <button key={idx} className="whitespace-nowrap bg-[#C59E39]/10 border border-[#C59E39]/20 text-[#C59E39] px-4 py-2 rounded-full text-xs font-bold hover:bg-[#C59E39] hover:text-white transition-all flex items-center gap-1.5 tap-scale">
            <span className="material-symbols-outlined text-sm">{s.icon}</span>
            {s.label}
          </button>
        ))}
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((m, i) => (
          <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} gap-1.5`}>
            <div className={`flex items-start gap-2.5 max-w-[85%] ${isAr ? 'flex-row-reverse' : ''}`}>
              {m.role === 'assistant' && (
                <div className="size-8 rounded-full bg-white border border-[#C59E39]/30 flex items-center justify-center shrink-0 mt-1 shadow-sm">
                  <span className="material-symbols-outlined text-[#C59E39] text-lg">auto_awesome</span>
                </div>
              )}
              <div className={`p-4 rounded-2xl shadow-sm ${
                m.role === 'user' 
                  ? 'bg-[#5D4037] text-white rounded-tr-none' 
                  : (isDarkMode ? 'bg-[#2D221F] text-gray-200 border-[#5D4037]' : 'bg-white text-[#5D4037] border-gray-100')
              } border`}>
                <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.content}</p>
                {m.role === 'assistant' && i > 0 && (
                  <div className="bg-[#FAF3E0]/50 dark:bg-black/20 p-3 rounded-lg border-l-4 border-[#C59E39] italic text-xs mt-3 opacity-80">
                     {isAr ? 'اقتباس من المصادر الرسمية...' : 'Quoted from official sources...'}
                  </div>
                )}
              </div>
            </div>
            <span className={`text-[10px] text-gray-400 font-medium ${isAr ? 'mr-10' : 'ml-10'}`}>{m.time}</span>

            {m.role === 'assistant' && i > 0 && (
              <div className={`flex gap-2 ${isAr ? 'mr-10' : 'ml-10'}`}>
                <button className={`px-3 py-1 rounded-full text-[10px] flex items-center gap-1 transition-colors ${isDarkMode ? 'bg-[#2D221F] text-gray-400 border border-white/5' : 'bg-white text-gray-600 border border-gray-100'}`}>
                  <span className="material-symbols-outlined text-xs">content_copy</span> {labels.copy}
                </button>
                <button className={`px-3 py-1 rounded-full text-[10px] flex items-center gap-1 transition-colors ${isDarkMode ? 'bg-[#2D221F] text-gray-400 border border-white/5' : 'bg-white text-gray-600 border border-gray-100'}`}>
                  <span className="material-symbols-outlined text-xs">share</span> {labels.share}
                </button>
              </div>
            )}
          </div>
        ))}
        {isLoading && (
          <div className="flex items-start gap-2.5">
            <div className="size-8 rounded-full bg-white border border-[#C59E39]/30 flex items-center justify-center shrink-0 mt-1 shadow-sm">
              <span className="material-symbols-outlined text-[#C59E39] text-lg">auto_awesome</span>
            </div>
            <div className="bg-white dark:bg-[#2D221F] p-4 rounded-2xl rounded-tl-none border border-[#C59E39]/20 flex gap-1.5">
               <div className="size-1.5 bg-[#C59E39] rounded-full animate-bounce"></div>
               <div className="size-1.5 bg-[#C59E39] rounded-full animate-bounce [animation-delay:0.1s]"></div>
               <div className="size-1.5 bg-[#C59E39] rounded-full animate-bounce [animation-delay:0.2s]"></div>
            </div>
          </div>
        )}
      </div>

      <div className={`p-4 border-t ${isDarkMode ? 'bg-[#1F1715] border-white/5' : 'bg-white border-gray-100'} shrink-0`}>
        <div className="flex items-center gap-2">
          <button className={`size-10 rounded-full flex items-center justify-center text-gray-500 hover:text-[#5D4037] transition-colors shrink-0 ${isDarkMode ? 'bg-[#2D221F]' : 'bg-gray-100'}`}>
            <span className="material-symbols-outlined">attach_file</span>
          </button>
          <div className="flex-1 relative">
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              className={`w-full border-none rounded-full px-5 py-3 text-sm focus:ring-2 focus:ring-[#C59E39] ${isDarkMode ? 'bg-[#2D221F] text-white placeholder:text-gray-500' : 'bg-gray-100 text-[#5D4037]'}`}
              placeholder={labels.placeholder}
              type="text"
            />
          </div>
          <button className="size-10 rounded-full bg-[#C59E39] flex items-center justify-center text-white shadow-lg transition-all active:scale-90 shrink-0">
            <span className="material-symbols-outlined">mic</span>
          </button>
          <button onClick={handleSend} className="size-10 rounded-full bg-[#5D4037] flex items-center justify-center text-white shadow-lg transition-all active:scale-90 shrink-0">
            <span className="material-symbols-outlined">send</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

