import React, { useState } from 'react';
import { COLORS, TAWAF_DUAS } from '../constants';

interface TawafCounterProps {
  language: string;
  isDarkMode: boolean;
}

const TawafCounter: React.FC<TawafCounterProps> = ({ language, isDarkMode }) => {
  const [count, setCount] = useState(0);
  const isAr = language === 'ar';

  const getLapText = (c: number) => {
    if (!isAr) return `Lap ${c} of 7`;
    const texts = ['', 'الأول', 'الثاني', 'الثالث', 'الرابع', 'الخامس', 'السادس', 'السابع'];
    return c > 0 ? `الشوط ${texts[c]}` : 'ابدأ الطواف';
  };

  const increment = () => { if (count < 7) setCount(prev => prev + 1); };
  const reset = () => setCount(0);

  return (
    <div className="px-6 py-6 space-y-6 animate-in slide-in-from-bottom-10 duration-500">
      <div className={`relative flex flex-col items-center justify-center p-12 rounded-[56px] border-2 transition-all shadow-2xl ${
        isDarkMode ? 'bg-[#251B19] border-[#5D4037]/40 shadow-black/40' : 'bg-white border-[#D4AF37]/10 shadow-[#C59E39]/5'
      }`}>
        <div className="relative w-64 h-64 flex items-center justify-center">
          <svg className="absolute w-full h-full -rotate-90">
            <circle cx="128" cy="128" r="110" fill="none" 
              stroke={isDarkMode ? '#3D2F2B' : '#F8F1E5'} 
              strokeWidth="20" 
            />
            <circle
              cx="128" cy="128" r="110" fill="none" stroke={COLORS.GOLD} strokeWidth="20"
              strokeDasharray={2 * Math.PI * 110}
              strokeDashoffset={2 * Math.PI * 110 * (1 - count / 7)}
              strokeLinecap="round"
              className="transition-all duration-1000 ease-out"
            />
          </svg>
          <div className="flex flex-col items-center z-10">
            <span className={`text-8xl font-black mb-1 font-amiri ${isDarkMode ? 'text-white' : 'text-[#5D4037]'}`}>{count}</span>
            <span className={`text-[11px] font-black uppercase tracking-[4px] ${isDarkMode ? 'text-[#C59E39]' : 'text-gray-400'}`}>
              {isAr ? 'أشواط' : 'Laps'}
            </span>
          </div>
        </div>

        <p className="mt-8 text-2xl font-black text-[#C59E39] font-amiri">
          {getLapText(count)}
        </p>

        <div className="mt-12 flex space-x-5 space-x-reverse w-full">
          <button
            onClick={increment}
            className="flex-1 py-6 bg-[#C59E39] text-white rounded-[32px] font-black shadow-xl shadow-[#C59E39]/20 tap-scale active:brightness-90 uppercase tracking-widest text-xs"
          >
            {isAr ? 'شوط جديد +' : 'Add Lap +'}
          </button>
          <button
            onClick={reset}
            className={`p-6 rounded-[32px] border-2 flex items-center justify-center tap-scale transition-colors ${
              isDarkMode 
                ? 'bg-[#1A1110] border-[#5D4037] text-[#C59E39] shadow-inner' 
                : 'bg-[#FAF3E0] border-[#D4AF37]/20 text-[#5D4037] shadow-sm'
            }`}
          >
            <span className="material-symbols-outlined text-3xl">refresh</span>
          </button>
        </div>
      </div>

      <div className={`p-8 rounded-[48px] border shadow-xl ${isDarkMode ? 'bg-[#251B19] border-[#5D4037]/30' : 'bg-white border-[#FAF3E0]'}`}>
         <div className={`flex items-center gap-3 mb-4 ${isAr ? 'flex-row-reverse text-right' : ''}`}>
           <div className="w-10 h-10 rounded-2xl bg-[#C59E39]/10 flex items-center justify-center">
              <span className="material-symbols-outlined text-[#C59E39]">auto_awesome</span>
           </div>
           <h4 className={`font-black text-sm uppercase tracking-widest ${isDarkMode ? 'text-white' : 'text-[#5D4037]'}`}>
             {isAr ? 'أذكار الطواف' : 'Tawaf Duas'}
           </h4>
         </div>
         <p className={`leading-relaxed font-amiri text-2xl text-center ${isDarkMode ? 'text-[#E5D3B3]' : 'text-[#5D4037]'}`}>
            {TAWAF_DUAS[0].text}
         </p>
      </div>
    </div>
  );
};

export default TawafCounter;

