}

const SaiCounter: React.FC<SaiCounterProps> = ({ language, isDarkMode }) => {
  const [laps, setLaps] = useState(0);
  const [direction, setDirection] = useState<'toMarwa' | 'toSafa'>('toMarwa');
  const isAr = language === 'ar';

  const increment = (newDir: 'toMarwa' | 'toSafa') => {
    if (laps < 7 && newDir !== direction) {
      setLaps(prev => prev + 1);
      setDirection(newDir);
    } else if (laps === 0 && newDir === 'toMarwa') {
      setLaps(1);
      setDirection('toMarwa');
    }
  };

  const reset = () => { setLaps(0); setDirection('toMarwa'); };

  return (
    <div className="px-6 py-6 space-y-6 animate-in slide-in-from-bottom-10 duration-500">
      <div className={`rounded-[56px] p-12 space-y-12 border-2 transition-all shadow-2xl ${
        isDarkMode ? 'bg-[#251B19] border-[#5D4037]/40 shadow-black/40' : 'bg-white border-[#D4AF37]/10 shadow-[#C59E39]/5'
      }`}>
        <div className="flex justify-between items-center relative">
          <div className="flex flex-col items-center z-10">
            <div className={`w-20 h-20 rounded-[28px] flex items-center justify-center transition-all duration-500 font-black text-xl shadow-lg ${
              direction === 'toSafa' || laps === 0 
                ? 'bg-[#C59E39] text-white shadow-[#C59E39]/40' 
                : (isDarkMode ? 'bg-[#1A1110] text-[#5D4037]' : 'bg-[#F8F1E5] text-gray-400')
            }`}>
              {isAr ? 'ص' : 'S'}
            </div>
            <span className="mt-3 text-[11px] font-black uppercase text-gray-500 tracking-[2px]">{isAr ? 'الصفا' : 'Safa'}</span>
          </div>

          <div className={`flex-1 h-2 mx-6 rounded-full relative overflow-hidden ${isDarkMode ? 'bg-[#1A1110]' : 'bg-[#F8F1E5]'}`}>
             <div className="absolute h-full bg-[#C59E39] transition-all duration-1000 shadow-[0_0_10px_rgba(197,158,57,0.5)]" 
               style={{ width: `${(laps/7) * 100}%`, [isAr ? 'right' : 'left']: 0 }} 
             />
          </div>

          <div className="flex flex-col items-center z-10">
            <div className={`w-20 h-20 rounded-[28px] flex items-center justify-center transition-all duration-500 font-black text-xl shadow-lg ${
              direction === 'toMarwa' 
                ? 'bg-[#C59E39] text-white shadow-[#C59E39]/40' 
                : (isDarkMode ? 'bg-[#1A1110] text-[#5D4037]' : 'bg-[#F8F1E5] text-gray-400')
            }`}>
              {isAr ? 'م' : 'M'}
            </div>
            <span className="mt-3 text-[11px] font-black uppercase text-gray-500 tracking-[2px]">{isAr ? 'المروة' : 'Marwa'}</span>
          </div>
        </div>

        <div className="flex flex-col items-center justify-center">
          <span className={`text-8xl font-black font-amiri ${isDarkMode ? 'text-white' : 'text-[#C59E39]'}`}>{laps}</span>
          <span className={`text-[11px] uppercase font-black tracking-[6px] mt-4 ${isDarkMode ? 'text-[#C59E39]/60' : 'text-gray-400'}`}>
            {isAr ? 'أشواط السعي' : 'Sa’i Laps'}
          </span>
        </div>

        <div className="grid grid-cols-2 gap-6">
          <button
            onClick={() => increment('toMarwa')}
            disabled={laps === 7 || (direction === 'toMarwa' && laps > 0)}
            className={`flex flex-col items-center p-10 rounded-[40px] transition-all tap-scale border-2 shadow-xl ${
              direction === 'toSafa' || laps === 0 
                ? 'bg-[#C59E39] border-[#C59E39] text-white shadow-[#C59E39]/30' 
                : (isDarkMode ? 'bg-[#1A1110] border-[#5D4037] text-[#5D4037] opacity-40' : 'bg-gray-50 border-gray-100 text-gray-300')
            }`}
          >
            <span className="material-symbols-outlined text-4xl mb-3">arrow_forward</span>
            <span className="text-[10px] font-black uppercase tracking-widest">{isAr ? 'إلى المروة' : 'To Marwa'}</span>
          </button>

          <button
            onClick={() => increment('toSafa')}
            disabled={laps === 7 || direction === 'toSafa'}
            className={`flex flex-col items-center p-10 rounded-[40px] transition-all tap-scale border-2 shadow-xl ${
              direction === 'toMarwa' 
                ? 'bg-[#C59E39] border-[#C59E39] text-white shadow-[#C59E39]/30' 
                : (isDarkMode ? 'bg-[#1A1110] border-[#5D4037] text-[#5D4037] opacity-40' : 'bg-gray-50 border-gray-100 text-gray-300')
            }`}
          >
            <span className="material-symbols-outlined text-4xl mb-3">arrow_back</span>
            <span className="text-[10px] font-black uppercase tracking-widest">{isAr ? 'إلى الصفا' : 'To Safa'}</span>
          </button>
        </div>

        <button onClick={reset} className={`w-full py-4 text-[11px] font-black uppercase tracking-[5px] tap-scale opacity-60 ${isDarkMode ? 'text-[#E5D3B3]' : 'text-gray-400'}`}>
          {isAr ? 'إعادة العداد' : 'Reset Counter'}
        </button>
      </div>
    </div>
  );
};

export default SaiCounter;

