import { GoogleGenAI } from "@google/genai";
import { AIMode } from "../types";

// Initialize the Google GenAI SDK with the API key from environment variables
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const askRitualAssistant = async (query: string, mode: AIMode, language: string) => {
  const instructions = {
    [AIMode.FATWA]: `أنت مفتي متخصص في مناسك الحج والعمرة. 
      يجب أن تكون إجاباتك مختصرة، مبنية على الدليل، ومستمدة حصرياً من الرئاسة العامة للبحوث العلمية والإفتاء بالمملكة العربية السعودية (alifta.gov.sa).
      إذا كان هناك اختلاف معتبر، فاذكره بإيجاز. اللغة: ${language}.`,
    [AIMode.TRANSLATION]: `You are a translator for religious terms used in the Haramain. 
      Translate the user's input accurately between ${language} and Arabic, focusing on ritual accuracy.`,
    [AIMode.EXPLANATION]: `أنت مرشد (رفيق). اشرح خطوات النسك (مثل صفة العمرة أو الحج) بوضوح وسهولة بناءً على ما ورد في موقع دار الإفتاء (alifta.gov.sa). 
      ركز على الأركان والواجبات والمواقع الجغرافية بدقة. اللغة: ${language}.`
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: query,
      config: {
        thinkingConfig: { thinkingBudget: 15000 },
        systemInstruction: instructions[mode] + " Always cite official sources at the bottom: alifta.gov.sa or alharamain.gov.sa"
      }
    });
    return response.text;
  } catch (error) {
    console.error("AI Error:", error);
    return "عذراً، تعذر الحصول على الإجابة حالياً. يرجى مراجعة الموقع الرسمي لدار الإفتاء alifta.gov.sa";
  }
};

