              </div>
            </div>

            <div className="flex flex-col gap-2">
              <label className={`text-[11px] font-bold uppercase tracking-widest px-1 ${isDarkMode ? 'text-[#C59E39]' : 'text-[#5D4037]'}`}>{t.accLabel}</label>
              <div className="relative">
                <select 
                  value={accessibility}
                  onChange={(e) => setAccessibility(e.target.value as AccessibilityMode)}
                  className={`w-full p-4 pr-12 rounded-2xl font-bold outline-none focus:ring-2 focus:ring-[#C59E39] border-2 transition-all ${
