              <label className={`text-[11px] font-bold uppercase tracking-widest px-1 ${isDarkMode ? 'text-[#C59E39]' : 'text-[#5D4037]'}`}>{t.natLabel}</label>
              <div className="relative">
                <select 
                  value={nationality}
                  onChange={(e) => setNationality(e.target.value)}
                  className={`w-full p-4 pr-12 rounded-2xl font-bold outline-none focus:ring-2 focus:ring-[#C59E39] border-2 transition-all ${
                    isDarkMode ? 'bg-[#2D221F] border-[#5D4037] text-white' : 'bg-white border-[#5D4037]/20 text-[#5D4037]'
                  }`}
                >
                  <option value="">{t.selectCountry}</option>
                  {Object.entries(t.nations).map(([code, name]) => (
                    <option key={code} value={code}>{name as string}</option>
                  ))}
                </select>
                <div className={`absolute ${isAr ? 'left-4' : 'right-4'} top-1/2 -translate-y-1/2 pointer-events-none`}>
                  <svg className="w-6 h-6 text-[#C59E39]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" /></svg>
                </div>
              </div>
            </div>
          </div>

          <div className="mt-auto pb-10 flex flex-col items-center">
            <button 
              onClick={() => setOnboarded(true)}
              className="w-full py-5 bg-[#5D4037] text-white font-black text-lg rounded-2xl shadow-xl shadow-[#5D4037]/20 tap-scale transition-all"
            >
              {t.nextBtn}
            </button>
            <button onClick={() => setOnboarded(true)} className={`w-full py-4 mt-2 font-bold text-sm opacity-60 ${isDarkMode ? 'text-[#C59E39]' : 'text-[#5D4037]'}`}>
              {t.skipBtn}
            </button>
          </div>
        </main>
      </div>
    );
  }

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab} 
      language={language} 
      isDarkMode={isDarkMode} 
      toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
    >
      {renderContent()}
    </Layout>
  );
};

